class Solution {
public:
    int racecar(int target) {
        queue<pair<int, int>> q;
        q.push({0, 1});
        unordered_set<string> visited;
        visited.insert("0 1");
        int steps = 0;
        while (!q.empty()) {
            int size = q.size();
            for (int i = 0; i < size; i++) {
                auto [pos, speed] = q.front();
                q.pop();
                if (pos == target) return steps;
                int nextPos = pos + speed;
                int nextSpeed = speed * 2;
                string next = to_string(nextPos) + " " + to_string(nextSpeed);
                if (nextPos >= 0 && visited.find(next) == visited.end()) {
                    q.push({nextPos, nextSpeed});
                    visited.insert(next);
                }
                nextSpeed = speed > 0 ? -1 : 1;
                next = to_string(pos) + " " + to_string(nextSpeed);
                if (visited.find(next) == visited.end()) {
                    q.push({pos, nextSpeed});
                    visited.insert(next);
                }
            }
            steps++;
        }
        return -1;
    }
};

